/* ══════════════════════════════════════════════════════
   ERROR BOUNDARY — catches any render crash and shows it
   on screen instead of silently going blank (production)
══════════════════════════════════════════════════════ */
class ErrorBoundary extends Component {
  constructor(props){ super(props); this.state={error:null}; }
  static getDerivedStateFromError(e){ return {error:e}; }
  componentDidCatch(e,info){ try{console.error("[Vedatime crash]",e,info);}catch(_){} }
  render(){
    if(this.state.error){
      const e=this.state.error;
      return(
        <div style={{minHeight:"100vh",background:"#0D0B1A",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",padding:32,fontFamily:"monospace",color:"#FF4444"}}>
          <div style={{fontSize:48,marginBottom:16}}>⚠️</div>
          <div style={{fontSize:20,fontWeight:900,marginBottom:12,color:"#FF6666"}}>Vedatime encountered an error</div>
          <div style={{background:"rgba(255,68,68,0.1)",border:"1px solid #FF444466",borderRadius:12,padding:"16px 20px",maxWidth:640,width:"100%",wordBreak:"break-all"}}>
            <div style={{color:"#FF8888",fontSize:14,fontWeight:700,marginBottom:8}}>{e.name}: {e.message}</div>
            <div style={{color:"rgba(255,255,255,0.5)",fontSize:11,lineHeight:1.6,whiteSpace:"pre-wrap"}}>{e.stack?.split("\n").slice(0,8).join("\n")}</div>
          </div>
          <button onClick={()=>this.setState({error:null})} style={{marginTop:20,padding:"10px 24px",borderRadius:20,border:"none",background:"#8B5CF6",color:"#fff",fontSize:14,fontWeight:700,cursor:"pointer"}}>Try Again</button>
        </div>
      );
    }
    return this.props.children;
  }
}

/* ══════════════════════════════════════════════════════
   RESPONSIVE + TIME HOOKS
══════════════════════════════════════════════════════ */
function useBreakpoint() {
  const get = () => { if(typeof window==="undefined")return"desktop"; const w=window.innerWidth; return w<768?"mobile":w<1100?"tablet":"desktop"; };
  const [bp,setBp]=useState(get);
  useEffect(()=>{ const h=()=>setBp(get()); window.addEventListener("resize",h); return()=>window.removeEventListener("resize",h); },[]);
  return bp;
}
function useCurrentTime() {
  const [now,setNow]=useState(new Date());
  useEffect(()=>{ const id=setInterval(()=>setNow(new Date()),1000); return()=>clearInterval(id); },[]);
  return now;
}
function getActiveMuhurat(now) {
  const h=now.getHours(), m=now.getMinutes(), t=h*60+m;
  if(t>=293&&t<=338) return{name:"Brahma Muhurat",good:true,c:"#5BA4F5"};
  if(t>=523&&t<=623) return{name:"Amrit Kaal",good:true,c:"#3DDC84"};
  if(t>=721&&t<=770) return{name:"Abhijit Muhurat",good:true,c:"#3DDC84"};
  if(t>=720&&t<=810) return{name:"Yamaganda",good:false,c:"#E67E22"};
  if(t>=810&&t<=870) return{name:"Gulika Kaal",good:false,c:"#E67E22"};
  if(t>=900&&t<=990) return{name:"Rahu Kaal",good:false,c:"#FF4444"};
  return null;
}

