const APP_NOW_UTC = new Date().toISOString();

function getLocalDateKeyForLocation(locationKey){
  const meta = getLocationMeta(locationKey);
  // V102: wrapped in try-catch — Intl.DateTimeFormat with timeZone throws RangeError on invalid tz strings
  try{
    const parts = new Intl.DateTimeFormat("en-CA", {
      timeZone: meta.tz,
      year: "numeric",
      month: "2-digit",
      day: "2-digit",
    }).formatToParts(new Date(APP_NOW_UTC));
    const year = parts.find(p=>p.type==="year")?.value;
    const month = parts.find(p=>p.type==="month")?.value;
    const day = parts.find(p=>p.type==="day")?.value;
    if(year&&month&&day) return `${year}-${month}-${day}`;
  }catch(_){}
  // Fallback: use device local date
  const d=new Date(APP_NOW_UTC);
  const y=d.getFullYear(),mo=String(d.getMonth()+1).padStart(2,"0"),dy=String(d.getDate()).padStart(2,"0");
  return `${y}-${mo}-${dy}`;
}

