/* ── Live days recalculation (FESTIVALS) — runs at app load ── */
(function(){
  const _now=new Date();
  const _today=new Date(_now.getFullYear(),_now.getMonth(),_now.getDate());
  const _yr=_now.getFullYear();
  FESTIVALS.forEach(f=>{
    let d=new Date(_yr,f.month,f.day);
    if(d<_today) d=new Date(_yr+1,f.month,f.day);
    f.days=Math.round((d-_today)/(864e5));
  });
})();

