/* ── Fuzzy bigram match — handles typos & misspellings ── */
function _fuzzy(needle,haystack){
  needle=needle.toLowerCase(); haystack=haystack.toLowerCase();
  if(haystack.includes(needle)) return true;
  if(needle.length<3) return false;
  // Build bigrams of needle, check how many appear in haystack
  let matched=0,total=0;
  for(let i=0;i<needle.length-1;i++){
    const g=needle.slice(i,i+2);
    total++;
    if(haystack.includes(g)) matched++;
  }
  return total>0&&matched/total>=0.5;
}
