function getBirthNakshatra(dateStr) {
  if (!dateStr) return null;
  const d=new Date(dateStr), start=new Date("1900-01-01");
  const days=Math.floor((d-start)/86400000);
  return NAKSHATRAS_LIST[((days%27)+27)%27];
}

