/* ══════════════════════════════════════════════════════
   AARTI VIDEO CONTROLS — proper React component
   Handles chant + video within the expanded aarti scene.
   Uses a stable chanting state so STOP never disappears
   mid-loop when audio system retries tiers.
══════════════════════════════════════════════════════ */
function AartiVideoControls({aartiData, S}) {
  // Separate chanting state so user controls audio independently from aarti scene
  const [isChanting, setIsChanting] = useState(false);
  function handleChant() {
    setIsChanting(true);
    startLoopingMantra(aartiData.mantra, aartiData.romanized || aartiData.mantra,
      () => setIsChanting(false), aartiData.deity + " Mantra");
  }
  function handleStop() {
    stopSpeech();
    setIsChanting(false);
  }
  return (
    <>
      <p style={{color:"rgba(255,255,255,0.75)",fontSize:14,fontFamily:"'Noto Sans Devanagari',serif",
        textAlign:"center",margin:"0 0 6px",lineHeight:1.7,fontWeight:600}}>
        {aartiData.mantra}
      </p>
      {isChanting && (
        <p style={{color:"#FF8C42",fontSize:11,fontWeight:800,textAlign:"center",margin:"0 0 10px",letterSpacing:0.5}}>
          🔊 CHANTING IN PROGRESS
        </p>
      )}
      <div style={{display:"flex",gap:8,justifyContent:"center",flexWrap:"wrap",alignItems:"center"}}>
        {isChanting ? (
          <button onClick={handleStop}
            style={{padding:"9px 20px",borderRadius:12,border:"1px solid rgba(255,255,255,0.3)",background:"rgba(255,255,255,0.12)",color:"#fff",fontSize:13,fontWeight:800,cursor:"pointer"}}>
            ⏹ Stop Chanting
          </button>
        ) : (
          <button onClick={handleChant}
            style={{padding:"9px 20px",borderRadius:12,border:"none",background:"linear-gradient(135deg,#FF8C42,#FF5722)",color:"#fff",fontSize:13,fontWeight:800,cursor:"pointer",boxShadow:"0 3px 12px rgba(255,87,34,0.4)"}}>
            🔊 Chant Mantra
          </button>
        )}
        <button onClick={()=>openVideo(aartiData.ytIds||[], aartiData.ytQ, aartiData.deity+" Aarti")}
          style={{padding:"9px 16px",borderRadius:10,background:"rgba(255,0,0,0.2)",color:"#FF9090",fontSize:12,fontWeight:800,cursor:"pointer",border:"1px solid rgba(255,0,0,0.3)"}}>
          ▶ Play Aarti Video
        </button>
        <button onClick={()=>openSharePanel(aartiData.deity+" Aarti", "🕉️ Today's Aarti: "+aartiData.deity+" | "+aartiData.mantra)}
          style={{padding:"9px 14px",borderRadius:10,border:"none",background:"rgba(255,255,255,0.08)",color:"rgba(255,255,255,0.7)",fontSize:12,fontWeight:700,cursor:"pointer"}}>
          📤 Share
        </button>
      </div>
    </>
  );
}

