        <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',gap:10,marginBottom:8,flexWrap:'wrap'}}><SecTitle emoji="✨" title="Your focus" S={S}/><button onClick={()=>window.dispatchEvent(new CustomEvent('dharma:open-onboarding'))} style={{padding:bp==='mobile'?'7px 10px':'8px 12px',borderRadius:12,border:'1px solid '+S.border,background:S.surface,color:S.text,fontSize:12,fontWeight:800,cursor:'pointer'}}>✏️ Edit</button></div>
