function PujaSamagriPanel({S,bp}){
  const pujas=Object.keys(PUJA_SAMAGRI);
  const[sel,setSel]=useState(pujas[0]);
  const[checked,setChecked]=useState({});
  const p=PUJA_SAMAGRI[sel];
  const toggle=(i)=>setChecked(prev=>({...prev,[sel+i]:!prev[sel+i]}));
  const done=p.items.filter((_,i)=>checked[sel+i]).length;
  const reset=()=>{const n={...checked};p.items.forEach((_,i)=>{delete n[sel+i];});setChecked(n);};
  const share=()=>{
    const unchecked=p.items.filter((_,i)=>!checked[sel+i]);
    const txt=`🛍️ *Puja Samagri — ${sel}*\n\n${unchecked.map(it=>`□ ${it.n}  (${it.q})`).join("\n")}\n\n🙏 Vedatime`;
    openSharePanel("Puja Samagri List",txt);
  };
  return(
    <div>
      <div style={{background:"linear-gradient(135deg,#1A0A2E,#0D1520)",borderRadius:18,padding:"16px 18px",marginBottom:14,border:"1px solid "+S.gold+"44",display:"flex",alignItems:"center",gap:12}}>
        <div style={{width:46,height:46,borderRadius:14,background:S.gold+"30",display:"flex",alignItems:"center",justifyContent:"center",fontSize:24,flexShrink:0}}>🛍️</div>
        <div>
          <h2 style={{color:"#FFFFFF",fontSize:16,fontWeight:900,margin:0}}>Puja Samagri List</h2>
          <p style={{color:"rgba(255,255,255,0.55)",fontSize:12,margin:"2px 0 0"}}>Shopping checklist for every puja — tick items as you gather them</p>
        </div>
      </div>
      <div style={{display:"flex",gap:6,flexWrap:"wrap",marginBottom:12}}>
        {pujas.map(pu=>(
          <button key={pu} onClick={()=>setSel(pu)}
            style={{padding:"6px 12px",borderRadius:20,border:"1px solid "+(sel===pu?PUJA_SAMAGRI[pu].color:S.border),background:sel===pu?PUJA_SAMAGRI[pu].color+"22":"transparent",color:sel===pu?PUJA_SAMAGRI[pu].color:S.muted,fontSize:11,fontWeight:sel===pu?800:500,cursor:"pointer"}}>
            {PUJA_SAMAGRI[pu].icon} {pu}
          </button>
        ))}
      </div>
      <div style={{background:S.card,borderRadius:14,padding:"12px 15px",marginBottom:12,border:"1px solid "+S.border}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8}}>
          <span style={{color:S.text,fontSize:13,fontWeight:800}}>{p.icon} {sel}</span>
          <span style={{color:done===p.items.length?S.green:S.muted,fontSize:12,fontWeight:700}}>{done}/{p.items.length} gathered</span>
        </div>
        <div style={{background:S.border,borderRadius:99,height:6,overflow:"hidden"}}>
          <div style={{background:"linear-gradient(90deg,"+p.color+","+p.color+"BB)",height:"100%",borderRadius:99,width:(done/p.items.length*100)+"%",transition:"width 0.3s ease"}}/>
        </div>
        {done===p.items.length&&<p style={{color:S.green,fontSize:12,fontWeight:700,margin:"8px 0 0",textAlign:"center"}}>✅ All gathered! You are ready for {sel}. 🙏</p>}
      </div>
      {p.items.map((item,i)=>(
        <div key={i} onClick={()=>toggle(i)}
          style={{background:checked[sel+i]?S.green+"0E":S.card,borderRadius:13,padding:"12px 14px",marginBottom:7,border:"1px solid "+(checked[sel+i]?S.green+"44":S.border),cursor:"pointer",display:"flex",gap:12,alignItems:"flex-start",opacity:checked[sel+i]?0.65:1,transition:"all 0.2s"}}>
          <div style={{width:24,height:24,borderRadius:7,border:"2px solid "+(checked[sel+i]?S.green:S.border),background:checked[sel+i]?S.green:"transparent",display:"flex",alignItems:"center",justifyContent:"center",fontSize:13,flexShrink:0,marginTop:1,color:"#fff",fontWeight:900}}>
            {checked[sel+i]?"✓":""}
          </div>
          <div style={{flex:1}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",gap:8}}>
              <p style={{color:S.text,fontSize:13,fontWeight:700,margin:0,textDecoration:checked[sel+i]?"line-through":"none"}}>{item.n}</p>
              <span style={{background:p.color+"22",color:p.color,fontSize:11,fontWeight:800,padding:"2px 8px",borderRadius:8,flexShrink:0,whiteSpace:"nowrap"}}>{item.q}</span>
            </div>
            <p style={{color:S.muted,fontSize:11,margin:"3px 0 0",lineHeight:1.5}}>{item.note}</p>
          </div>
        </div>
      ))}
      <div style={{display:"flex",gap:8,marginTop:6}}>
        <button onClick={share} style={{flex:1,padding:"12px",borderRadius:13,border:"none",background:"linear-gradient(90deg,#25D366,#128C7E)",color:"#FFFFFF",fontSize:13,fontWeight:700,cursor:"pointer"}}>
          📤 Share on WhatsApp
        </button>
        <button onClick={reset} style={{padding:"12px 14px",borderRadius:13,border:"1px solid "+S.border,background:"transparent",color:S.muted,fontSize:12,fontWeight:600,cursor:"pointer"}}>
          🔄 Reset
        </button>
      </div>
    </div>
  );
}

