function CityCelebrationsPanel({S,bp,selectedLocation,isPremium,onPremium}){
  const[showFestIdx,setShowFestIdx]=useState(null);
  const city=LOCATION_OPTIONS.find(l=>l.key===selectedLocation)||LOCATION_OPTIONS[0];
  const cityData=CITY_CELEBRATIONS[selectedLocation]||null;
  const festivals=cityData?Object.keys(cityData):[];
  const[selFest,setSelFest]=useState(festivals[0]||"");
  const venues=cityData&&selFest?cityData[selFest]:[];

  // upcoming festivals for this city
  const today=new Date();
  const mm=today.getMonth()+1;
  const allFests=[...festivals].sort();

  return(
    <div>
      <div style={{background:"linear-gradient(135deg,#0D1A2E,#0A2035)",borderRadius:18,padding:"14px 16px",marginBottom:14,border:"1px solid "+S.gold+"44",display:"flex",alignItems:"center",gap:12}}>
        <div style={{width:44,height:44,borderRadius:14,background:S.gold+"30",display:"flex",alignItems:"center",justifyContent:"center",fontSize:22,flexShrink:0}}>🎊</div>
        <div>
          <h2 style={{color:"#FFFFFF",fontSize:15,fontWeight:900,margin:0}}>City &amp; Festival Celebrations</h2>
          <p style={{color:"rgba(255,255,255,0.55)",fontSize:11,margin:"2px 0 0"}}>Where to celebrate festivals in {city.label}</p>
        </div>
      </div>

      <p style={{color:S.gold,fontSize:12,fontWeight:800,margin:"0 0 8px",textTransform:"uppercase",letterSpacing:1}}>🗺️ How Cities Celebrate</p>

      {!cityData?(
        <div style={{background:S.card,borderRadius:14,padding:"28px 20px",textAlign:"center",border:"1px solid "+S.border}}>
          <p style={{fontSize:28,margin:"0 0 8px"}}>🏙️</p>
          <p style={{color:S.text,fontSize:14,fontWeight:700,margin:"0 0 6px"}}>Coming Soon for {city.label}</p>
          <p style={{color:S.muted,fontSize:12,margin:0}}>Switch to: Mumbai, Delhi, Varanasi, Kolkata, Prayagraj, Haridwar, Ayodhya, Vrindavan, Mathura, Jaipur, Ahmedabad, Pune, Bengaluru, Tirupati, Hyderabad, Chennai, Mysuru, Ujjain, Rishikesh, Puri, Somnath, Mauritius, Bali, or Kuala Lumpur to see local celebration venues.</p>
        </div>
      ):(
        <>
          {/* Festival selector */}
          <div style={{background:S.card,borderRadius:14,padding:12,marginBottom:12,border:"1px solid "+S.border}}>
            <p style={{color:S.gold,fontSize:11,fontWeight:800,margin:"0 0 8px",textTransform:"uppercase",letterSpacing:1}}>🎉 Select Festival</p>
            <div style={{display:"flex",flexWrap:"wrap",gap:6}}>
              {allFests.map(f=>(
                <button key={f} onClick={()=>setSelFest(f)}
                  style={{padding:"5px 10px",borderRadius:20,border:"1px solid "+(selFest===f?S.gold:S.border),background:selFest===f?"linear-gradient(135deg,"+S.saffron+","+S.gold+")":"transparent",color:selFest===f?"#fff":S.muted,fontSize:11,fontWeight:selFest===f?800:600,cursor:"pointer"}}>
                  {f}
                </button>
              ))}
            </div>
          </div>

          {/* Venues */}
          {selFest&&venues.length>0&&(
            <div>
              <p style={{color:S.text,fontSize:13,fontWeight:800,margin:"0 0 10px"}}>🗺️ {selFest} Celebrations in {city.label}</p>
              {venues.map((v,i)=>(
                <div key={i} style={{background:S.card,borderRadius:14,padding:"12px 14px",marginBottom:10,border:"1px solid "+S.border,display:"flex",gap:12,alignItems:"flex-start"}}>
                  <div style={{width:38,height:38,borderRadius:10,background:S.saffron+"22",display:"flex",alignItems:"center",justifyContent:"center",fontSize:18,flexShrink:0}}>🕌</div>
                  <div style={{flex:1}}>
                    <p style={{color:S.text,fontSize:13,fontWeight:800,margin:"0 0 3px"}}>{v.place}</p>
                    <p style={{color:S.muted,fontSize:11,margin:"0 0 6px",lineHeight:1.5}}>{v.note}</p>
                    <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
                      <a href={`https://maps.google.com/?q=${encodeURIComponent((v.place||"")+" "+city.label)}`} target="_blank" rel="noreferrer"
                        style={{display:"inline-flex",alignItems:"center",gap:4,padding:"4px 10px",borderRadius:20,background:S.gold+"22",border:"1px solid "+S.gold+"44",color:S.gold,fontSize:11,fontWeight:700,textDecoration:"none"}}>
                        📍 View on Map
                      </a>
                      <a href={`https://maps.google.com/?q=${encodeURIComponent((v.place||"")+" "+city.label)}&layer=transit`} target="_blank" rel="noreferrer"
                        style={{display:"inline-flex",alignItems:"center",gap:4,padding:"4px 10px",borderRadius:20,background:"#0EA5E922",border:"1px solid #0EA5E944",color:"#0EA5E9",fontSize:11,fontWeight:700,textDecoration:"none"}}>
                        🗺️ Directions
                      </a>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </>
      )}
    </div>
  );
}

/* ══════════════════════════════════════════════════════
   DEITY OF DAY PANEL
══════════════════════════════════════════════════════ */
function DeityOfDayPanel({S,bp}){
  const today=new Date();
  const dow=today.getDay(); // 0=Sun
  const deity=DEITIES_OF_DAY[dow];
  const moon=getMoonPhase(today);

  const PUJA_STEPS={
    0:["Wake before sunrise, face east","Offer red flowers (hibiscus) and water (Arghya) to the rising sun","Light a ghee lamp","Recite Aditya Hridayam or Surya Ashtakam","Offer 12 Surya Namaskars facing east"],
    1:["Fast on Mondays for Shiva's blessings","Offer milk, honey, and Bilva leaves on Shiva lingam","Light camphor and incense","Recite Om Namah Shivaya 108 times","Keep the mind calm and peaceful all day"],
    2:["Visit Hanuman or Mangal temple early morning","Offer red flowers, sindoor, and sesame oil","Light a sesame oil lamp","Recite Hanuman Chalisa or Mangal mantra","Donate red lentils (masoor dal) to the poor"],
    3:["Worship Lord Vishnu or Vithal on Wednesday","Offer green tulsi leaves and green flowers","Light incense (agarbatti)","Recite Vishnu Sahasranama or Vithal mantra","Study scriptures or do educational activities"],
    4:["Offer yellow flowers to Guru/Brihaspati","Wear yellow clothes if possible","Recite Guru mantra and seek blessings of elders","Donate yellow items (turmeric, yellow dal)","Fast or eat only once for guru's grace"],
    5:["Worship Goddess Lakshmi on Friday evening","Offer lotus flowers, kheer, and coconut","Light fragrant incense and rose petals","Recite Sri Lakshmi Ashtottara (108 names)","Donate money or food to the needy"],
    6:["Recite Shani Chalisa or Shani Ashtakam","Offer sesame oil and black sesame to Shani deity","Donate black items — sesame, mustard oil","Avoid major new undertakings today","Serve the elderly and the less fortunate"],
  };

  const steps=PUJA_STEPS[dow]||[];

  return(
    <div>
      {/* Deity Card */}
      <div style={{background:"linear-gradient(135deg,"+deity.color+"22,"+deity.color+"08)",borderRadius:18,padding:"16px",marginBottom:14,border:"1px solid "+deity.color+"55"}}>
        <div style={{display:"flex",alignItems:"center",gap:14,marginBottom:12}}>
          <div style={{width:56,height:56,borderRadius:16,background:deity.color+"33",display:"flex",alignItems:"center",justifyContent:"center",fontSize:30,flexShrink:0}}>
            {deity.emoji}
          </div>
          <div>
            <p style={{color:S.muted,fontSize:11,fontWeight:700,margin:"0 0 2px",textTransform:"uppercase",letterSpacing:1}}>Today's Presiding Deity</p>
            <h2 style={{color:"#FFFFFF",fontSize:20,fontWeight:900,margin:"0 0 2px"}}>{deity.name}</h2>
            <p style={{color:deity.color,fontSize:12,fontWeight:700,margin:0}}>{deity.significance}</p>
          </div>
        </div>
        <div style={{background:"rgba(0,0,0,0.25)",borderRadius:12,padding:"10px 12px",marginBottom:10}}>
          <p style={{color:S.muted,fontSize:11,fontWeight:700,margin:"0 0 4px",textTransform:"uppercase",letterSpacing:1}}>Sacred Mantra</p>
          <p style={{color:"#FFFFFF",fontSize:14,fontWeight:800,margin:0,fontStyle:"italic"}}>"{deity.mantra}"</p>
        </div>
        <p style={{color:"rgba(255,255,255,0.65)",fontSize:12,margin:0,lineHeight:1.6}}>{deity.desc}</p>
      </div>

      {/* Today's Puja Steps */}
      <div style={{background:S.card,borderRadius:14,padding:"12px 14px",marginBottom:12,border:"1px solid "+S.border}}>
        <p style={{color:S.gold,fontSize:11,fontWeight:800,margin:"0 0 10px",textTransform:"uppercase",letterSpacing:1}}>🪔 Today's Puja Guide</p>
        {steps.map((step,i)=>(
          <div key={i} style={{display:"flex",gap:10,alignItems:"flex-start",marginBottom:8}}>
            <div style={{width:22,height:22,borderRadius:"50%",background:deity.color+"33",border:"1px solid "+deity.color+"55",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0,fontSize:11,fontWeight:800,color:deity.color}}>{i+1}</div>
            <p style={{color:S.text,fontSize:12,margin:0,paddingTop:2,lineHeight:1.5}}>{step}</p>
          </div>
        ))}
      </div>

      {/* Moon Phase Card */}
      <div style={{background:S.card,borderRadius:14,padding:"12px 14px",border:"1px solid "+S.border}}>
        <p style={{color:S.gold,fontSize:11,fontWeight:800,margin:"0 0 10px",textTransform:"uppercase",letterSpacing:1}}>🌙 Current Moon Phase</p>
        <div style={{display:"flex",alignItems:"center",gap:12,marginBottom:10}}>
          <div style={{width:50,height:50,borderRadius:"50%",background:moon.color+"33",border:"1px solid "+moon.color+"55",display:"flex",alignItems:"center",justifyContent:"center",fontSize:26,flexShrink:0}}>{moon.emoji}</div>
          <div>
            <p style={{color:"#FFFFFF",fontSize:16,fontWeight:900,margin:"0 0 2px"}}>{moon.name}</p>
            <div style={{height:4,width:100,background:S.border,borderRadius:4,overflow:"hidden",marginBottom:4}}>
              <div style={{height:"100%",width:(moon.pct*100)+"%",background:"linear-gradient(90deg,"+moon.color+","+moon.color+"99)",borderRadius:4}}/>
            </div>
            <p style={{color:S.muted,fontSize:11,margin:0}}>{Math.round(moon.pct*100)}% illuminated</p>
          </div>
        </div>
        <p style={{color:"rgba(255,255,255,0.65)",fontSize:12,margin:0,lineHeight:1.6}}>{moon.significance}</p>
      </div>
    </div>
  );
}

