function LiveDarshanPanel({S,bp}){
  const[filter,setFilter]=useState("All");
  const[showMore,setShowMore]=useState(false);
  const[activeD,setActiveD]=useState(null);
  const PAGE=6;
  const states=["All",...[...new Set(LIVE_DARSHAN_DATA.map(d=>d.deity))].sort()];
  const filtered=filter==="All"?LIVE_DARSHAN_DATA:LIVE_DARSHAN_DATA.filter(d=>d.deity===filter);
  const visible=showMore?filtered:filtered.slice(0,PAGE);
  return(
    <div style={{display:"flex",flexDirection:"column",gap:12}}>
      <div style={{background:"linear-gradient(135deg,rgba(255,120,50,0.12),rgba(255,192,64,0.10))",borderRadius:16,padding:"14px 16px",border:"1px solid rgba(255,192,64,0.3)"}}>
        <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:8}}>
          <span style={{fontSize:24}}>🛕</span>
          <div>
            <h3 style={{color:S.text,fontSize:15,fontWeight:900,margin:0}}>Live Temple Darshan</h3>
            <p style={{color:S.muted,fontSize:11,margin:"2px 0 0"}}>12 sacred temples · Watch live aarti &amp; darshan in-app</p>
          </div>
        </div>
        <div style={{display:"flex",gap:5,flexWrap:"wrap"}}>
          {["All","Shiva","Vishnu","Krishna","Ganesha","Durga","Lakshmi","Sai Baba","Meenakshi (Parvati)","Waheguru (Sikh)","Ganga Mata","Ayyappa"].filter(d=>d==="All"||LIVE_DARSHAN_DATA.some(x=>x.deity===d)).map(d=>(
            <button key={d} onClick={()=>setFilter(d)}
              style={{padding:"4px 10px",borderRadius:12,border:"1px solid "+(filter===d?S.saffron:S.border),background:filter===d?S.saffron+"22":"transparent",color:filter===d?S.saffron:S.muted,fontSize:11,fontWeight:filter===d?700:500,cursor:"pointer"}}>
              {d}
            </button>
          ))}
        </div>
      </div>
      {visible.map(t=>(
        <div key={t.id} style={{background:S.card,borderRadius:14,padding:"12px 14px",border:"1px solid "+S.border}}>
          <div style={{display:"flex",gap:12,alignItems:"flex-start"}}>
            <div style={{width:44,height:44,borderRadius:12,background:S.saffron+"22",display:"flex",alignItems:"center",justifyContent:"center",fontSize:22,flexShrink:0}}>{t.icon}</div>
            <div style={{flex:1,minWidth:0}}>
              <p style={{color:S.text,fontWeight:800,fontSize:13,margin:0}}>{t.name}</p>
              <p style={{color:S.muted,fontSize:11,margin:"2px 0 4px"}}>{t.state} · {t.deity}</p>
              <p style={{color:S.muted,fontSize:11,lineHeight:1.5,margin:"0 0 8px"}}>{t.note}</p>
              <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
                <button onClick={()=>setActiveD(activeD?.id===t.id?null:t)}
                  style={{padding:"6px 12px",borderRadius:10,border:"none",background:activeD?.id===t.id?"#FF8C00":"linear-gradient(135deg,#FF7040,#FF5522)",color:"#fff",fontSize:11,fontWeight:800,cursor:"pointer",display:"flex",alignItems:"center",gap:5}}>
                  {activeD?.id===t.id?"▼ Close":"▶ Watch in App"}
                </button>
                <button onClick={()=>openExternal(t.liveUrl,"_blank")}
                  style={{padding:"6px 12px",borderRadius:10,border:"1px solid #FF000066",background:"transparent",color:"#FF6060",fontSize:11,fontWeight:800,cursor:"pointer",display:"flex",alignItems:"center",gap:5}}>
                  <span>▶</span> Live on YouTube
                </button>
                {t.officialUrl&&<a href={t.officialUrl} target="_blank" rel="noopener noreferrer"
                  style={{padding:"5px 11px",borderRadius:10,border:"1px solid "+S.border,background:"transparent",color:S.muted,fontSize:11,fontWeight:600,textDecoration:"none",display:"flex",alignItems:"center",gap:4}}>
                  🌐 Official Site
                </a>}
              </div>
              {activeD?.id===t.id&&(
                <div style={{marginTop:10}}>
                  <YouTubeInlinePlayer ytIds={t.ytIds} ytSearch={t.ytSearch} title={t.name} S={S}/>
                  <p style={{color:S.muted,fontSize:11,margin:"6px 0 0"}}>▲ Recorded aarti — for live stream, tap "Live on YouTube"</p>
                </div>
              )}
            </div>
          </div>
        </div>
      ))}
      {filtered.length>PAGE&&(
        <button onClick={()=>setShowMore(v=>!v)}
          style={{width:"100%",padding:"9px",borderRadius:12,border:"1px solid "+S.border,background:"transparent",color:S.gold,fontSize:12,fontWeight:700,cursor:"pointer"}}>
          {showMore?`↑ Show fewer`:`＋ View all ${filtered.length} temples`}
        </button>
      )}
      <div style={{background:S.card,borderRadius:12,padding:"11px 14px",border:"1px solid "+S.border}}>
        <p style={{color:S.muted,fontSize:11,margin:0,lineHeight:1.6}}>🛕 Tap <strong style={{color:S.text}}>Watch Live</strong> to open the temple's live stream on YouTube. Most temples broadcast morning aarti (4–7 AM IST), midday puja, and evening aarti (6–8 PM IST). Official site links go to the temple's website.</p>
      </div>
    </div>
  );
}

/* ── YouTubeInlinePlayer — wrapper around centralized VideoPlayer
   Keeps backward compatibility with existing call sites.
   All logic is now in VideoPlayer above. ─────────────────── */
function YouTubeInlinePlayer({ytId,ytIds,ytSearch,title,S,onClose}){
  const searchUrl = `https://www.youtube.com/results?search_query=${encodeURIComponent(ytSearch || title || "Hindu devotional")}`;
  return (
    <div style={{borderRadius:14,padding:"14px 16px",background:"rgba(0,0,0,0.5)",border:"1px solid rgba(255,255,255,0.1)",display:"flex",flexDirection:"column",gap:10}}>
      <div>
        <p style={{color:"#FF9800",fontSize:12,fontWeight:800,margin:0}}>Video opens on YouTube</p>
        <p style={{color:"rgba(255,255,255,0.45)",fontSize:11,margin:"3px 0 0"}}>Uses the same reliable YouTube search flow as the app video sheet.</p>
      </div>
      <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
        <a href={searchUrl} target="_blank" rel="noopener noreferrer"
          style={{padding:"9px 14px",borderRadius:10,background:"rgba(255,0,0,0.18)",border:"1px solid rgba(255,0,0,0.35)",color:"#FF8A80",fontSize:12,fontWeight:800,textDecoration:"none"}}>
          ▶ Watch on YouTube
        </a>
      </div>
    </div>
  );
}



/* ── Hindi TTS engine — Google Translate TTS (genuine Indian Hindi) ─
   Tier 1: Google Translate TTS API → 100% Indian Hindi accent
            Same engine used by Google Translate app
            URL: translate.google.com/translate_tts?tl=hi
   Tier 2: Web Speech API → Google hi-IN voice (Chrome/Android)
   Tier 3: Any hi-IN device voice
   ─────────────────────────────────────────────────────────────── */


/* ══════════════════════════════════════════════════════
   BHAJAN / MEDIA HUB PANEL
══════════════════════════════════════════════════════ */
function BhajanMediaHubPanel({S,bp}){
  const[cat,setCat]=useState("All");
  const[active,setActive]=useState(null);
  const[showReadText,setShowReadText]=useState(false);
  const cats=["All","Bhajan","Aarti","Mantra","Katha","Audiobook"];
  const filtered=cat==="All"?BHAJAN_LIBRARY:BHAJAN_LIBRARY.filter(b=>b.cat===cat);
  return(
    <div style={{display:"flex",flexDirection:"column",gap:12}}>
      <div style={{background:"linear-gradient(135deg,rgba(255,120,50,0.12),rgba(255,192,64,0.10))",borderRadius:16,padding:"14px 16px",border:"1px solid rgba(255,192,64,0.3)"}}>
        <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:8}}>
          <span style={{fontSize:24}}>🎵</span>
          <div>
            <h3 style={{color:S.text,fontSize:15,fontWeight:900,margin:0}}>Bhajan &amp; Spiritual Media</h3>
            <p style={{color:S.muted,fontSize:11,margin:"2px 0 0"}}>{BHAJAN_LIBRARY.length} curated items · Bhajans, Aartis, Mantras, Katha · Sanskrit &amp; Hindi content</p>
          </div>
        </div>
        <div style={{display:"flex",gap:5,flexWrap:"wrap"}}>
          {cats.map(c=>(
            <button key={c} onClick={()=>{setCat(c);setActive(null);}}
              style={{padding:"4px 11px",borderRadius:12,border:"1px solid "+(cat===c?S.saffron:S.border),background:cat===c?S.saffron+"22":"transparent",color:cat===c?S.saffron:S.muted,fontSize:11,fontWeight:cat===c?700:500,cursor:"pointer"}}>
              {c}
            </button>
          ))}
        </div>
      </div>

      {/* Active player */}
      {active&&(
        <div style={{background:S.card,borderRadius:16,padding:14,border:"1px solid "+active.color+"55"}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:10}}>
            <div>
              <p style={{color:S.text,fontWeight:800,fontSize:13,margin:0}}>{active.icon} {active.title}</p>
              <p style={{color:S.muted,fontSize:11,margin:"2px 0 0"}}>{active.artist} · {active.deity}</p>
            </div>
            <div style={{display:"flex",gap:6}}>
              {active.text&&(
                <button onClick={()=>setShowReadText(v=>!v)}
                  title="Read text"
                  style={{padding:"5px 10px",borderRadius:8,border:"1px solid "+(showReadText?"#FFC040":"#FFC04066"),background:showReadText?"#FFC04022":"transparent",color:"#FFC040",fontSize:11,fontWeight:700,cursor:"pointer"}}>
                  📖 {showReadText?"Hide":"Text"}
                </button>
              )}
              <button onClick={()=>{setActive(null);setShowReadText(false);}}
                style={{padding:"5px 10px",borderRadius:8,border:"1px solid "+S.border,background:"transparent",color:S.muted,fontSize:11,cursor:"pointer"}}>
                ✕
              </button>
            </div>
          </div>
          <div style={{display:"flex",gap:8,flexWrap:"wrap",marginBottom:4}}>
            <button onClick={()=>openVideo(active.ytIds||[], active.ytSearch||active.title, active.title)}
              style={{padding:"8px 14px",borderRadius:10,border:"none",background:"linear-gradient(135deg,#FF4500,#CC3300)",color:"#fff",fontSize:12,fontWeight:800,cursor:"pointer"}}>
              ▶ Watch Video
            </button>
          </div>
          {active.text&&showReadText&&(
            <div style={{background:S.bg,borderRadius:10,padding:"12px 14px",border:"1px solid "+S.border,marginTop:8}}>
              <p style={{color:S.gold,fontSize:11,fontWeight:800,margin:"0 0 6px"}}>📖 पाठ (Text)</p>
              <pre style={{color:S.text,fontSize:12,lineHeight:1.9,margin:0,whiteSpace:"pre-wrap",fontFamily:"inherit"}}>{active.text}</pre>
              <button onClick={()=>speakMantra(active.text, active.text, null, "Hindi")}
                style={{marginTop:8,padding:"6px 14px",borderRadius:8,border:"1px solid #FFC04066",background:"#FFC04022",color:"#FFC040",fontSize:11,fontWeight:700,cursor:"pointer"}}>
                🔊 Chant in Hindi
              </button>
            </div>
          )}
          <p style={{color:S.muted,fontSize:11,margin:"8px 0 0",lineHeight:1.6}}>{active.desc}</p>
        </div>
      )}

      <div style={{display:"grid",gridTemplateColumns:bp==="mobile"?"1fr":"1fr 1fr",gap:10}}>
        {filtered.map(b=>(
          <div key={b.id}
            style={{background:S.card,borderRadius:14,padding:"12px 14px",border:"1px solid "+(active?.id===b.id?b.color:S.border),cursor:"pointer",transition:"border 0.2s"}}
            onClick={()=>setActive(active?.id===b.id?null:b)}>
            <div style={{display:"flex",gap:10,alignItems:"flex-start"}}>
              <div style={{width:40,height:40,borderRadius:10,background:b.color+"22",display:"flex",alignItems:"center",justifyContent:"center",fontSize:20,flexShrink:0}}>{b.icon}</div>
              <div style={{flex:1,minWidth:0}}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",gap:4}}>
                  <p style={{color:S.text,fontWeight:800,fontSize:12,margin:0,lineHeight:1.3}}>{b.title}</p>
                  <span style={{padding:"2px 7px",borderRadius:8,background:b.color+"22",color:b.color,fontSize:11,fontWeight:700,whiteSpace:"nowrap",flexShrink:0}}>{b.cat}</span>
                </div>
                <p style={{color:S.muted,fontSize:11,margin:"2px 0 5px"}}>{b.artist}</p>
                <p style={{color:S.muted,fontSize:11,lineHeight:1.5,margin:"0 0 8px"}}>{b.desc.substring(0,75)}{b.desc.length>75?"…":""}</p>
                <div style={{display:"flex",gap:5,flexWrap:"wrap"}}>
                  <button onClick={e=>{e.stopPropagation();openVideo(b.ytIds||[], b.ytSearch||b.title, b.title);}}
                    style={{padding:"4px 10px",borderRadius:8,border:"none",background:b.color,color:"#fff",fontSize:11,fontWeight:800,cursor:"pointer"}}>
                    ▶ Watch in App
                  </button>
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>

      <div style={{background:S.card,borderRadius:12,padding:"13px 15px",border:"1px solid "+S.border}}>
        <p style={{color:S.gold,fontSize:11,fontWeight:800,margin:"0 0 5px"}}>ℹ️ How it works</p>
        <p style={{color:S.muted,fontSize:11,margin:0,lineHeight:1.7}}>
          Each item first tries in-app playback. If YouTube blocks embedding for that source, the player now falls back to opening the best matching result on YouTube so you are not left with a dead video option. Click any item to open the player and also read the full text or hear audio.
        </p>
      </div>
    </div>
  );
}

/* ══════════════════════════════════════════════════════
   SPIRITUAL BOOKS PANEL
══════════════════════════════════════════════════════ */
function SpiritualBooksPanel({S,bp,lang}){
  return(
    <div style={{display:"flex",flexDirection:"column",gap:12}}>
      <div style={{background:"linear-gradient(135deg,rgba(255,120,50,0.12),rgba(255,192,64,0.10))",borderRadius:16,padding:"14px 16px",border:"1px solid rgba(255,192,64,0.3)"}}>
        <div style={{display:"flex",alignItems:"center",gap:10}}>
          <span style={{fontSize:24}}>📚</span>
          <div>
            <h3 style={{color:S.text,fontSize:15,fontWeight:900,margin:0}}>Free Spiritual Library</h3>
            <p style={{color:S.muted,fontSize:11,margin:"2px 0 0"}}>Sacred texts, scriptures &amp; classics — free to read online</p>
          </div>
        </div>
      </div>
      <div style={{display:"grid",gridTemplateColumns:bp==="mobile"?"1fr":"1fr 1fr",gap:10}}>
        {SPIRITUAL_BOOKS.map((bk,i)=>(
          <a key={i} href={bk.url} target="_blank" rel="noopener noreferrer"
            style={{background:S.card,borderRadius:14,padding:"13px 14px",border:"1px solid "+S.border,textDecoration:"none",display:"block",transition:"border 0.2s"}}>
            <div style={{display:"flex",gap:10,alignItems:"flex-start"}}>
              <div style={{width:40,height:40,borderRadius:10,background:S.saffron+"22",display:"flex",alignItems:"center",justifyContent:"center",fontSize:20,flexShrink:0}}>{bk.icon}</div>
              <div>
                <p style={{color:S.text,fontWeight:800,fontSize:12,margin:"0 0 2px"}}>{bk.title}</p>
                <p style={{color:S.muted,fontSize:11,margin:"0 0 5px"}}>{bk.author} · {bk.lang}</p>
                <p style={{color:S.muted,fontSize:11,lineHeight:1.5,margin:0}}>{bk.desc}</p>
                <p style={{color:S.saffron,fontSize:11,fontWeight:700,margin:"6px 0 0"}}>📖 Read Free →</p>
              </div>
            </div>
          </a>
        ))}
      </div>
    </div>
  );
}

/* ══════════════════════════════════════════════════════
   DIGITAL MALA COUNTER PANEL
══════════════════════════════════════════════════════ */
function MalaCounterPanel({S,bp}){
  const[count,setCount]=useState(0);
  const[malas,setMalas]=useState(0);
  const[mantra,setMantra]=useState("Om Namah Shivaya");
  const[log,setLog]=useState([]);
  const MANTRAS_LIST=["Om Namah Shivaya","Hare Krishna","Om Namo Bhagavate Vasudevaya","Om Gam Ganapataye Namah","Om Dum Durgayai Namah","Gayatri Mantra","Om Shreem Hreem Kleem","Ram Ram Ram","Om Aim Saraswatyai Namah","Om Hanumate Namah","Om Shanti Shanti Shanti"];
  const BEAD_COUNT=108;
  const tap=()=>{
    const next=count+1;
    if(next>=BEAD_COUNT){
      const newMalas=malas+1;
      setMalas(newMalas);
      setCount(0);
      setLog(l=>[{mantra,malas:newMalas,time:new Date().toLocaleTimeString()},...l.slice(0,9)]);
    } else setCount(next);
    if(typeof window!=="undefined"&&window.navigator&&window.navigator.vibrate) window.navigator.vibrate(30);
  };
  const reset=()=>{setCount(0);setMalas(0);setLog([]);};
  const pct=(count/BEAD_COUNT)*100;
  const beadsLeft=BEAD_COUNT-count;
  return(
    <div style={{display:"flex",flexDirection:"column",gap:12}}>
      <div style={{background:"linear-gradient(135deg,rgba(255,120,50,0.12),rgba(255,192,64,0.10))",borderRadius:16,padding:"14px 16px",border:"1px solid rgba(255,192,64,0.3)"}}>
        <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:8}}>
          <span style={{fontSize:24}}>📿</span>
          <div>
            <h3 style={{color:S.text,fontSize:15,fontWeight:900,margin:0}}>Digital Japa Mala</h3>
            <p style={{color:S.muted,fontSize:11,margin:"2px 0 0"}}>108-bead counter · Track your japa practice</p>
          </div>
        </div>
        <select value={mantra} onChange={e=>setMantra(e.target.value)}
          style={{width:"100%",padding:"8px 12px",borderRadius:10,border:"1px solid "+S.border,background:S.card,color:S.text,fontSize:12,fontWeight:600,outline:"none"}}>
          {MANTRAS_LIST.map(m=><option key={m} value={m}>{m}</option>)}
        </select>
      </div>
      {/* Main counter */}
      <div style={{background:S.card,borderRadius:18,padding:"20px 16px",border:"1px solid "+S.border,textAlign:"center"}}>
        {/* Circular progress */}
        <div style={{position:"relative",width:160,height:160,margin:"0 auto 16px",display:"flex",alignItems:"center",justifyContent:"center"}}>
          <svg width="160" height="160" style={{position:"absolute",top:0,left:0,transform:"rotate(-90deg)"}}>
            <circle cx="80" cy="80" r="70" fill="none" stroke={S.border} strokeWidth="8"/>
            <circle cx="80" cy="80" r="70" fill="none" stroke={S.saffron} strokeWidth="8"
              strokeDasharray={`${2*Math.PI*70}`}
              strokeDashoffset={`${2*Math.PI*70*(1-pct/100)}`}
              strokeLinecap="round" style={{transition:"stroke-dashoffset 0.2s"}}/>
          </svg>
          <button onClick={tap}
            style={{width:110,height:110,borderRadius:"50%",border:"none",background:"linear-gradient(135deg,"+S.saffron+","+S.gold+")",color:"#fff",fontSize:16,fontWeight:900,cursor:"pointer",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:2,boxShadow:"0 4px 20px "+S.saffron+"55",userSelect:"none",WebkitTapHighlightColor:"transparent"}}>
            <span style={{fontSize:32}}>📿</span>
            <span style={{fontSize:13}}>{count}</span>
          </button>
        </div>
        <p style={{color:S.text,fontSize:13,fontWeight:800,margin:"0 0 4px"}}>{mantra}</p>
        <p style={{color:S.muted,fontSize:11,margin:"0 0 12px"}}>{beadsLeft} beads left · {malas} mala{malas!==1?"s":""} completed</p>
        <div style={{display:"flex",gap:20,justifyContent:"center",marginBottom:12}}>
          <div style={{textAlign:"center"}}>
            <p style={{color:S.saffron,fontSize:28,fontWeight:900,margin:0}}>{malas}</p>
            <p style={{color:S.muted,fontSize:11,margin:0}}>Malas Done</p>
          </div>
          <div style={{textAlign:"center"}}>
            <p style={{color:S.gold,fontSize:28,fontWeight:900,margin:0}}>{malas*108+count}</p>
            <p style={{color:S.muted,fontSize:11,margin:0}}>Total Chants</p>
          </div>
        </div>
        <p style={{color:S.muted,fontSize:11,margin:"0 0 12px"}}>Tap the mala to count each chant</p>
        <button onClick={reset} style={{padding:"7px 18px",borderRadius:10,border:"1px solid "+S.border,background:"transparent",color:S.muted,fontSize:11,fontWeight:700,cursor:"pointer"}}>↺ Reset</button>
      </div>
      {log.length>0&&(
        <div style={{background:S.card,borderRadius:14,padding:"12px 14px",border:"1px solid "+S.border}}>
          <p style={{color:S.gold,fontSize:11,fontWeight:800,margin:"0 0 8px",textTransform:"uppercase",letterSpacing:1}}>Recent Completions</p>
          {log.map((l,i)=>(
            <div key={i} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"5px 0",borderBottom:i<log.length-1?"1px solid "+S.border:"none"}}>
              <p style={{color:S.text,fontSize:11,fontWeight:700,margin:0}}>{l.mantra}</p>
              <p style={{color:S.muted,fontSize:11,margin:0}}>Mala #{l.malas} · {l.time}</p>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

