  "Hasta":{deity:"Savitar (Sun)",symbol:"Hand",element:"Earth",lord:"Moon",qualities:"Skilled, crafty, healing hands",favorable:"Arts, crafts, healing, trading",avoid:"Nothing significant",lucky:"Green, White",stone:"Pearl",daily:"Excellent craftsperson energy. Ideal for any work with hands — art, surgery, trading, building. Chant Surya Mantra.",weekly:"Best: Monday, Sunday"},
