/* V101: StablePoseImg — multi-URL fallback chain.
   Tries: primary Wikimedia thumbnail → full-res Wikimedia (no /thumb/ path) → SVG fallback.
   Uses loading="eager" so images load immediately when visible (not deferred by lazy-load).
   Uses referrerPolicy="strict-origin-when-cross-origin" to send referrer header to Wikimedia CDN.
   Referrer-Policy: no-referrer was the root cause of Wikimedia image failures in v98/v99.
   NOTE: crossOrigin="anonymous" removed — forces CORS mode which causes failures when server
   doesn't return Access-Control-Allow-Origin headers. No crossOrigin attr = simple (no-CORS) mode. */
function StablePoseImg({src, alt, fallback, style, onClick, srcs}) {
  // srcs: optional array of URL strings to try in order; falls back to SVG last
  const allSrcs = srcs && srcs.length ? [...srcs.filter(Boolean), fallback] : [src, fallback].filter(Boolean);
  const [idx, setIdx] = useState(0);
  useEffect(() => { setIdx(0); }, [src]);
  const current = allSrcs[idx] || fallback;
  return <img
    src={current}
    alt={alt}
    loading="eager"
    referrerPolicy="strict-origin-when-cross-origin"
    onClick={onClick}
    onError={() => {
      if (idx < allSrcs.length - 1) setIdx(i => i + 1);
    }}
    style={style}
  />;
}

/* ══════════════════════════════════════════════════════
   PRANAYAMA BREATHING TIMER
   Genuine interactive wellness tool — visual animated
   breathing circle with inhale / hold / exhale phases.
   Three techniques: 4-7-8, Box Breathing, Nadi Shodhana.
══════════════════════════════════════════════════════ */
const PRANAYAMA_TECHNIQUES = [
  { id:"478",   name:"4-7-8 Breathing",   desc:"Calms the nervous system and reduces anxiety. Inhale 4s, hold 7s, exhale 8s.",     in:4, hold:7, out:8,  color:"#5BA4F5", icon:"🌊" },
  { id:"box",   name:"Box Breathing",      desc:"Used by Navy SEALs for focus and stress resilience. Equal 4-second phases.",         in:4, hold:4, out:4,  color:"#3DDC84", icon:"⬛" },
  { id:"nadi",  name:"Nadi Shodhana",      desc:"Alternate nostril breathing. Balances the ida and pingala nadis. Deeply calming.",  in:4, hold:4, out:8,  color:"#FF7040", icon:"🕉️" },
];
function PranayamaTimer({S,bp}) {
  const [technique, setTechnique] = useState(PRANAYAMA_TECHNIQUES[0]);
  const [phase, setPhase] = useState(null); // null | "inhale" | "hold" | "exhale"
  const [countdown, setCountdown] = useState(0);
  const [rounds, setRounds] = useState(0);
  const [total, setTotal] = useState(0);
  const timerRef = useRef(null);
  const phaseRef = useRef(null);
  const roundRef = useRef(0);

  const phases = [
    { name:"inhale", label:"Breathe In",  dur: technique.in,   color:"#5BA4F5" },
    { name:"hold",   label:"Hold",         dur: technique.hold, color:"#FFD700" },
    { name:"exhale", label:"Breathe Out", dur: technique.out,  color:"#3DDC84" },
  ];

  const stop = useCallback(() => {
    clearInterval(timerRef.current);
    setPhase(null); setCountdown(0);
  }, []);

  const runPhase = useCallback((phaseIdx, count) => {
    const ph = phases[phaseIdx];
    setPhase(ph.name);
    setCountdown(count !== undefined ? count : ph.dur);
    let c = count !== undefined ? count : ph.dur;
    clearInterval(timerRef.current);
    timerRef.current = setInterval(() => {
      c -= 1;
      setCountdown(c);
      setTotal(t => t + 1);
      if (c <= 0) {
        clearInterval(timerRef.current);
        const next = (phaseIdx + 1) % 3;
        if (next === 0) {
          roundRef.current += 1;
          setRounds(roundRef.current);
        }
        runPhase(next);
      }
    }, 1000);
  }, [technique]); // eslint-disable-line

  const start = () => { roundRef.current = 0; setRounds(0); setTotal(0); runPhase(0); };
  useEffect(() => () => clearInterval(timerRef.current), []);
  useEffect(() => { if (phase) { stop(); } }, [technique]); // eslint-disable-line

  const currentPhaseObj = phases.find(p => p.name === phase);
  const phaseColor = currentPhaseObj?.color || technique.color;
  const progress = phase ? ((phases.find(p=>p.name===phase)?.dur - countdown) / (phases.find(p=>p.name===phase)?.dur || 1)) : 0;
  const circleSize = bp === "mobile" ? 160 : 200;
  const r = (circleSize / 2) - 14;
  const circ = 2 * Math.PI * r;
  const dash = circ * (phase === "inhale" ? progress : phase === "hold" ? 1 : 1 - progress);

  return (
    <div style={{marginBottom:16}}>
      <div style={{background:"linear-gradient(135deg,rgba(91,164,245,0.08),rgba(61,220,132,0.05))",borderRadius:18,padding:"18px 16px",border:"1px solid rgba(91,164,245,0.2)"}}>
        <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:14}}>
          <span style={{fontSize:22}}>🫁</span>
          <div>
            <h3 style={{color:S.text,fontSize:17,fontWeight:900,margin:0}}>Pranayama Timer</h3>
            <p style={{color:S.muted,fontSize:13,margin:0}}>Guided breathing practice with visual cues</p>
          </div>
        </div>

        {/* Technique selector */}
        <div style={{display:"flex",gap:6,flexWrap:"wrap",marginBottom:16}}>
          {PRANAYAMA_TECHNIQUES.map(t=>(
            <button key={t.id} onClick={()=>setTechnique(t)}
              style={{padding:"7px 14px",borderRadius:20,border:`1px solid ${t.id===technique.id?t.color:S.border}`,
                background:t.id===technique.id?t.color+"22":"transparent",
                color:t.id===technique.id?t.color:S.muted,fontSize:12,fontWeight:t.id===technique.id?800:500,cursor:"pointer"}}>
              {t.icon} {t.name}
            </button>
          ))}
        </div>

        {/* Visual circle + countdown */}
        <div style={{display:"flex",flexDirection:bp==="mobile"?"column":"row",gap:20,alignItems:"center",marginBottom:16}}>
          <div style={{position:"relative",width:circleSize,height:circleSize,flexShrink:0,display:"flex",alignItems:"center",justifyContent:"center"}}>
            <svg width={circleSize} height={circleSize} style={{position:"absolute",top:0,left:0,transform:"rotate(-90deg)"}}>
              <circle cx={circleSize/2} cy={circleSize/2} r={r} fill="none" stroke={S.border} strokeWidth={8}/>
              {phase && <circle cx={circleSize/2} cy={circleSize/2} r={r} fill="none" stroke={phaseColor} strokeWidth={8}
                strokeDasharray={`${dash} ${circ}`} strokeLinecap="round"
                style={{transition:"stroke-dasharray 0.8s linear, stroke 0.4s"}}/>}
            </svg>
            <div style={{textAlign:"center",zIndex:1}}>
              {phase ? <>
                <div style={{color:phaseColor,fontSize:40,fontWeight:900,lineHeight:1,fontVariantNumeric:"tabular-nums"}}>{countdown}</div>
                <div style={{color:phaseColor,fontSize:14,fontWeight:800,marginTop:4}}>{currentPhaseObj?.label}</div>
              </> : <>
                <div style={{color:S.muted,fontSize:36}}>🧘</div>
                <div style={{color:S.muted,fontSize:13,marginTop:4}}>Ready</div>
              </>}
            </div>
          </div>
          <div style={{flex:1}}>
            <p style={{color:S.muted,fontSize:13,lineHeight:1.75,margin:"0 0 12px"}}>{technique.desc}</p>
            <div style={{display:"flex",gap:8,flexWrap:"wrap",marginBottom:12}}>
              {phases.map(ph=>(
                <div key={ph.name} style={{background:ph.name===phase?ph.color+"22":S.surface,border:`1px solid ${ph.name===phase?ph.color:S.border}`,
                  borderRadius:10,padding:"6px 12px",transition:"all 0.3s"}}>
                  <div style={{color:ph.name===phase?ph.color:S.muted,fontSize:11,fontWeight:700,textTransform:"uppercase",letterSpacing:0.5}}>{ph.label}</div>
                  <div style={{color:ph.name===phase?ph.color:S.text,fontSize:16,fontWeight:900}}>{ph.dur}s</div>
                </div>
              ))}
            </div>
            {rounds > 0 && <div style={{background:S.surface,borderRadius:10,padding:"8px 14px",marginBottom:12,display:"flex",gap:16}}>
              <span style={{color:S.green,fontSize:13,fontWeight:700}}>✦ {rounds} round{rounds>1?"s":""} completed</span>
              <span style={{color:S.muted,fontSize:13}}>{Math.floor(total/60)}:{String(total%60).padStart(2,"0")} elapsed</span>
            </div>}
            <div style={{display:"flex",gap:8}}>
              {!phase
                ? <button onClick={start} style={{padding:"10px 24px",borderRadius:12,border:"none",background:`linear-gradient(135deg,${technique.color},${technique.color}AA)`,color:"#fff",fontSize:14,fontWeight:800,cursor:"pointer"}}>▶ Start</button>
                : <button onClick={stop} style={{padding:"10px 24px",borderRadius:12,border:"1px solid rgba(255,60,40,0.4)",background:"rgba(255,60,40,0.25)",color:"#FF6060",fontSize:14,fontWeight:800,cursor:"pointer"}}>⏹ Stop</button>
              }
            </div>
          </div>
        </div>
        <p style={{color:S.muted,fontSize:12,margin:0,lineHeight:1.6}}>💡 Breathe through the nose. Practice on an empty stomach. Sit comfortably with spine erect. Stop if you feel dizzy.</p>
      </div>
    </div>
  );
}

